// SSM wire codec — the `[u32 count][payload…]` frame helpers and the IEEE-754
// binary16 conversions behind the RWKV-7 f16 state wire
// (`export/import_*_state_f16` in `wasm_bindings_ssm`).
//
// Lives OUTSIDE the `#[cfg(all(target_arch = "wasm32", feature = "ssm-wasm"))]`
// bindings module so (a) the native test suite can gate the conversions
// bit-exactly (the exhaustive `f16_roundtrip` sweeps below), and (b) native
// benches (`bench-batch-marginal`) can time the codec on real 2560-shape state
// frames. The wasm bindings re-export/consume these verbatim — there is exactly
// one codec for a layer's recurrent state on the f16 wire.

/// Append `v` little-endian.
pub fn put_u32(buf: &mut Vec<u8>, v: u32) {
    buf.extend_from_slice(&v.to_le_bytes());
}

/// Append `[u32 count][f32 LE…]`.
pub fn put_f32s(buf: &mut Vec<u8>, xs: &[f32]) {
    put_u32(buf, xs.len() as u32);
    for &x in xs {
        buf.extend_from_slice(&x.to_le_bytes());
    }
}

/// Read a little-endian u32 at `*off`, advancing it.
pub fn take_u32(b: &[u8], off: &mut usize) -> u32 {
    let v = u32::from_le_bytes(b[*off..*off + 4].try_into().unwrap());
    *off += 4;
    v
}

/// Read a `[u32 count][f32 LE…]` frame at `*off` into `out`, advancing it.
pub fn take_f32s(b: &[u8], off: &mut usize, out: &mut Vec<f32>) {
    let n = take_u32(b, off) as usize;
    out.clear();
    out.reserve(n);
    for _ in 0..n {
        out.push(f32::from_le_bytes(b[*off..*off + 4].try_into().unwrap()));
        *off += 4;
    }
}

// ── fp16 wire variants — HALVE the on-wire recurrent state (the ~2MB WKV blob is the
// bytes-on-wire cost per inter-station hop). The state is a recurrent ACTIVATION, not a
// weight: fp16 (~3 sig digits, O(1) magnitudes) is plenty, and the loss is bounded — each
// hop re-derives the state, it never compounds across the matvecs. `[u32 count][f16…]`,
// so the element count stays exact; only storage precision drops 4→2 bytes.
// Self-contained IEEE-754 binary16 conversions (round-to-nearest-even, handles
// subnormals/Inf/NaN) — no cross-module/feature dependency on the ssm-wasm build.

/// f32 → binary16 bits (the wire's encode direction).
pub fn f32_to_f16_bits(x: f32) -> u16 {
    let bits = x.to_bits();
    let sign = ((bits >> 16) & 0x8000) as u16;
    let exp = ((bits >> 23) & 0xff) as i32;
    let mant = bits & 0x007f_ffff;
    if exp == 0xff {
        // Inf / NaN
        return sign | 0x7c00 | if mant != 0 { 0x0200 } else { 0 };
    }
    let e = exp - 127 + 15;
    if e >= 0x1f {
        return sign | 0x7c00; // overflow → Inf
    }
    if e <= 0 {
        if e < -10 {
            return sign; // underflow → ±0
        }
        // subnormal
        let mant_full = mant | 0x0080_0000;
        let shift = (14 - e) as u32;
        let mut half = (mant_full >> shift) as u16;
        if (mant_full >> (shift - 1)) & 1 != 0 {
            half += 1;
        }
        return sign | half;
    }
    let mut half = ((e as u16) << 10) | ((mant >> 13) as u16);
    if mant & 0x1000 != 0 {
        // round-to-nearest-even (carry into exp is handled by the +1)
        half += 1;
    }
    sign | half
}

/// binary16 bits → f32 (the wire's decode direction; exact — every f16 is an f32).
pub fn f16_bits_to_f32(h: u16) -> f32 {
    let neg = (h & 0x8000) != 0;
    let exp = ((h >> 10) & 0x1f) as u32;
    let mant = (h & 0x03ff) as u32;
    let signbit = if neg { 0x8000_0000u32 } else { 0 };
    if exp == 0x1f {
        return f32::from_bits(signbit | 0x7f80_0000 | (mant << 13)); // Inf / NaN
    }
    if exp == 0 {
        // subnormal (or ±0): value = mant · 2^-24, exact for mant ≤ 1023.
        let val = (mant as f32) * (1.0f32 / 16_777_216.0);
        return if neg { -val } else { val };
    }
    let exp32 = exp + (127 - 15);
    f32::from_bits(signbit | (exp32 << 23) | (mant << 13))
}

// ── Branchless lane formulas (the simd128 kernels' per-lane math) ────────────
// Written once as SCALAR functions so the native test suite can prove them
// BIT-IDENTICAL to the reference conversions above (exhaustive 65,536-pattern
// sweep for decode; exhaustive-roundtrip + dense boundary sweeps for encode).
// The wasm kernels below execute the SAME integer ops (plus one exact
// integer→float convert-and-scale) per lane — wasm int/f32 ops are
// IEEE-deterministic, so twin == reference ⇒ SIMD == reference.

/// Lane formula for f16 → f32, all-integer except the exact subnormal rebuild
/// (`mant · 2⁻²⁴` — exact: mant ≤ 1023 and the scale is a power of two, and the
/// result ≥ 2⁻²⁴ is a NORMAL f32, so no double rounding exists to disagree).
#[inline]
fn f16_lane_to_f32_bits(h: u16) -> u32 {
    let h = h as u32;
    let sign = (h & 0x8000) << 16;
    let em = h & 0x7fff; // exponent+mantissa
    // Normalized: shift into f32 position, rebias 15 → 127 (+112 exponents).
    let norm = (em << 13).wrapping_add(112 << 23);
    // Inf/NaN (exp = 31): saturate the exponent to 255 — another +112 lands
    // 143 → 255 exactly, keeping the NaN payload `mant << 13` intact.
    let infnan = norm.wrapping_add(112 << 23);
    // Subnormal/zero (exp = 0): em IS the mantissa; value = em · 2⁻²⁴.
    let sub = ((em as f32) * (1.0 / 16_777_216.0)).to_bits();
    let mut bits = if em >= 0x7c00 { infnan } else { norm };
    if em < 0x0400 {
        bits = sub;
    }
    sign | bits
}

/// Lane formula for the f32 → f16 VECTOR path — valid ONLY for the plain-normal
/// class `113 ≤ exp ≤ 142` (result exponent 1..=30 pre-round). Everything else
/// (zero/subnormal/underflow, overflow, Inf/NaN) is the SPECIAL class the wasm
/// kernel routes to the scalar [`f32_to_f16_bits`] — bit-exact by delegation.
/// In-range: `(bits >>13) - (112 << 10)` re-biases exponent and keeps the top
/// 10 mantissa bits in place; `+ round-bit` reproduces the reference's
/// round-half-up INCLUDING the carry into the exponent (142/full-mantissa
/// rounds up to 0x7c00 = Inf, exactly like the reference).
#[inline]
fn f32_lane_to_f16_bits_normal(bits: u32) -> u16 {
    let sign = ((bits >> 16) & 0x8000) as u32;
    let half = ((bits & 0x7fff_ffff) >> 13) - (112 << 10);
    let rounded = half + ((bits >> 12) & 1);
    (sign | rounded) as u16
}

/// Is `bits` outside the encode vector path's plain-normal class?
#[inline]
fn f32_lane_is_special(bits: u32) -> bool {
    let exp = (bits >> 23) & 0xff;
    !(113..143).contains(&exp)
}

/// Scalar twin of the full SIMD encode dispatch (vector formula + special
/// fallback) — what the tests sweep against [`f32_to_f16_bits`].
#[cfg(test)]
#[inline]
fn f32_to_f16_bits_lanewise(x: f32) -> u16 {
    let bits = x.to_bits();
    if f32_lane_is_special(bits) {
        f32_to_f16_bits(x)
    } else {
        f32_lane_to_f16_bits_normal(bits)
    }
}

// ── simd128 bulk kernels (wasm32 only; native keeps the scalar loops) ────────
// Per-function `#[target_feature(enable = "simd128")]` — NOT crate-wide — the
// same discipline as `dot_q8_row_simd128` (a missing attribute compiles v128
// intrinsics as un-inlined per-op CALLS; that bug class cost the batched base
// step ~10× on the live fleet).

/// Decode 8 f16 (16 LE bytes) → 8 f32, the [`f16_lane_to_f32_bits`] formula per
/// lane. Unaligned loads/stores are fine on wasm (alignment is only a hint).
#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn take_f16x8_simd128(src: *const u8, dst: *mut f32) {
    use core::arch::wasm32::*;
    #[inline(always)]
    unsafe fn quad(w: v128) -> v128 {
        // w: 4 × u32 lanes each holding one f16's bits (≤ 0x7fff after masking).
        let sign = i32x4_shl(v128_and(w, u32x4_splat(0x8000)), 16);
        let em = v128_and(w, u32x4_splat(0x7fff));
        let norm = i32x4_add(i32x4_shl(em, 13), u32x4_splat(112 << 23));
        let infnan = i32x4_add(norm, u32x4_splat(112 << 23));
        // em ≤ 0x7fff fits signed convert exactly; ×2⁻²⁴ is an exact pow-2 scale.
        let sub = f32x4_mul(f32x4_convert_i32x4(em), f32x4_splat(1.0 / 16_777_216.0));
        let bits = v128_bitselect(infnan, norm, u32x4_ge(em, u32x4_splat(0x7c00)));
        let bits = v128_bitselect(sub, bits, u32x4_lt(em, u32x4_splat(0x0400)));
        v128_or(bits, sign)
    }
    let h = v128_load(src as *const v128); // 8 × u16
    let lo = u32x4_extend_low_u16x8(h);
    let hi = u32x4_extend_high_u16x8(h);
    v128_store(dst as *mut v128, quad(lo));
    v128_store(dst.add(4) as *mut v128, quad(hi));
}

/// Encode 8 f32 → 8 f16 (16 LE bytes). Returns `false` when ANY lane is outside
/// the plain-normal class — the caller then encodes those 8 with the scalar
/// reference (bit-exact by delegation; recurrent-state activations make the
/// special class rare, so the vector path is the steady state).
#[cfg(target_arch = "wasm32")]
#[target_feature(enable = "simd128")]
unsafe fn put_f16x8_simd128(src: *const f32, dst: *mut u8) -> bool {
    use core::arch::wasm32::*;
    let a = v128_load(src as *const v128);
    let b = v128_load(src.add(4) as *const v128);
    // Special-class check on all 8 lanes first (exp < 113 || exp >= 143).
    let ea = v128_and(u32x4_shr(a, 23), u32x4_splat(0xff));
    let eb = v128_and(u32x4_shr(b, 23), u32x4_splat(0xff));
    let sp_a = v128_or(u32x4_lt(ea, u32x4_splat(113)), u32x4_ge(ea, u32x4_splat(143)));
    let sp_b = v128_or(u32x4_lt(eb, u32x4_splat(113)), u32x4_ge(eb, u32x4_splat(143)));
    if v128_any_true(v128_or(sp_a, sp_b)) {
        return false;
    }
    #[inline(always)]
    unsafe fn quad(w: v128) -> v128 {
        // [`f32_lane_to_f16_bits_normal`] per lane, in u32 lanes.
        let sign = v128_and(u32x4_shr(w, 16), u32x4_splat(0x8000));
        let half = i32x4_sub(
            u32x4_shr(v128_and(w, u32x4_splat(0x7fff_ffff)), 13),
            u32x4_splat(112 << 10),
        );
        let rounded = i32x4_add(half, v128_and(u32x4_shr(w, 12), u32x4_splat(1)));
        v128_or(rounded, sign)
    }
    // Values are 0..=0xffff → the UNSIGNED narrow is exact (the signed one
    // would saturate anything ≥ 0x8000, i.e. every negative number).
    let packed = u16x8_narrow_i32x4(quad(a), quad(b));
    v128_store(dst as *mut v128, packed);
    true
}

/// Append `[u32 count][f16 LE…]` (each `x` encoded via [`f32_to_f16_bits`]).
/// wasm32: simd128 bulk kernel, 8 values per pass (scalar-reference fallback per
/// 8-group when any lane is subnormal/overflow/Inf/NaN, scalar tail) —
/// bit-identical to the scalar loop (the `f16_codec` sweep tests + the
/// batch-wave smoke's byte-stability check gate it).
pub fn put_f16s(buf: &mut Vec<u8>, xs: &[f32]) {
    put_u32(buf, xs.len() as u32);
    #[cfg(target_arch = "wasm32")]
    {
        let n = xs.len();
        let start = buf.len();
        buf.resize(start + n * 2, 0);
        let dst = &mut buf[start..];
        let mut i = 0usize;
        while i + 8 <= n {
            // SAFETY: 8 f32 readable at xs[i..], 16 bytes writable at dst[2i..];
            // wasm v128 loads/stores carry no alignment requirement.
            let vec_ok = unsafe { put_f16x8_simd128(xs.as_ptr().add(i), dst.as_mut_ptr().add(i * 2)) };
            if !vec_ok {
                for k in i..i + 8 {
                    dst[k * 2..k * 2 + 2].copy_from_slice(&f32_to_f16_bits(xs[k]).to_le_bytes());
                }
            }
            i += 8;
        }
        for k in i..n {
            dst[k * 2..k * 2 + 2].copy_from_slice(&f32_to_f16_bits(xs[k]).to_le_bytes());
        }
        return;
    }
    #[allow(unreachable_code)]
    for &x in xs {
        buf.extend_from_slice(&f32_to_f16_bits(x).to_le_bytes());
    }
}

/// Read a `[u32 count][f16 LE…]` frame at `*off` into `out` (decoded to f32),
/// advancing it. wasm32: simd128 bulk kernel, 8 values per pass + scalar tail —
/// bit-identical to the scalar loop (exhaustive 65,536-pattern gate).
pub fn take_f16s(b: &[u8], off: &mut usize, out: &mut Vec<f32>) {
    let n = take_u32(b, off) as usize;
    out.clear();
    #[cfg(target_arch = "wasm32")]
    {
        // Bounds up front (the scalar loop's slice indexing checked per element).
        let src = &b[*off..*off + n * 2];
        out.resize(n, 0.0);
        let mut i = 0usize;
        while i + 8 <= n {
            // SAFETY: 16 bytes readable at src[2i..], 8 f32 writable at out[i..].
            unsafe { take_f16x8_simd128(src.as_ptr().add(i * 2), out.as_mut_ptr().add(i)) };
            i += 8;
        }
        for k in i..n {
            let h = u16::from_le_bytes([src[k * 2], src[k * 2 + 1]]);
            out[k] = f16_bits_to_f32(h);
        }
        *off += n * 2;
        return;
    }
    #[allow(unreachable_code)]
    {
        out.reserve(n);
        for _ in 0..n {
            let h = u16::from_le_bytes(b[*off..*off + 2].try_into().unwrap());
            out.push(f16_bits_to_f32(h));
            *off += 2;
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// K3 gate, decode: the branchless lane formula (the simd128 kernel's
    /// per-lane math) is BIT-identical to the reference over ALL 65,536 f16
    /// patterns — every normal, both zeros, every subnormal, ±Inf, and every
    /// NaN payload.
    #[test]
    fn f16_decode_lane_formula_exhaustive() {
        for h in 0..=u16::MAX {
            let want = f16_bits_to_f32(h).to_bits();
            let got = f16_lane_to_f32_bits(h);
            assert_eq!(got, want, "h={h:#06x}: lane {got:#010x} != ref {want:#010x}");
        }
    }

    /// K3 gate, encode: the SIMD dispatch (vector formula for plain normals,
    /// scalar delegation for the special class) matches the reference over
    /// (a) the exhaustive f16-representable set (all 65,536 patterns decoded
    /// and re-encoded — every exactly-representable value incl. subnormal/
    /// Inf/NaN), and (b) a dense deterministic f32 sweep across every exponent
    /// with mantissa patterns covering every rounding class: round-down,
    /// round-up, tie (half-up in the reference), carry-into-exponent,
    /// carry-to-Inf, underflow-to-zero, subnormal shifts, and NaN payloads.
    #[test]
    fn f32_encode_lane_dispatch_sweeps() {
        // (a) exhaustive over f16-representable values.
        for h in 0..=u16::MAX {
            let x = f16_bits_to_f32(h);
            assert_eq!(
                f32_to_f16_bits_lanewise(x),
                f32_to_f16_bits(x),
                "roundtrip h={h:#06x} (x={x:e})"
            );
        }
        // (b) all 256 exponents × both signs × mantissa rounding classes.
        let mants: [u32; 20] = [
            0x000000, 0x000001, 0x000fff, 0x001000, 0x001001, // below/at/above the round bit
            0x001fff, 0x002000, 0x002fff, 0x003000, 0x003001, // even/odd steps of the kept lsb
            0x123456, 0x2aaaaa, 0x400000, 0x555555, 0x654321,
            0x7fdfff, 0x7fe000, 0x7fefff, 0x7ff000, 0x7fffff, // top-of-range carries
        ];
        for exp in 0u32..=255 {
            for sign in [0u32, 0x8000_0000] {
                for &m in &mants {
                    let bits = sign | (exp << 23) | m;
                    let x = f32::from_bits(bits);
                    assert_eq!(
                        f32_to_f16_bits_lanewise(x),
                        f32_to_f16_bits(x),
                        "bits={bits:#010x} (exp={exp}, x={x:e})"
                    );
                }
            }
        }
        // (b′) dense mantissa scan on the boundary exponents (subnormal shift
        // depths, the vector-path edges 112/113 and 142/143, Inf/NaN).
        for exp in [0u32, 101, 102, 103, 112, 113, 114, 141, 142, 143, 254, 255] {
            for sign in [0u32, 0x8000_0000] {
                let mut m = 0u32;
                while m < (1 << 23) {
                    let bits = sign | (exp << 23) | m;
                    let x = f32::from_bits(bits);
                    assert_eq!(
                        f32_to_f16_bits_lanewise(x),
                        f32_to_f16_bits(x),
                        "bits={bits:#010x} (exp={exp})"
                    );
                    m += 0x2f; // stride hits every low-bit rounding pattern
                }
            }
        }
    }

    /// The wire frame helpers roundtrip (and the f16 wire is idempotent after
    /// one rounding — the batch-wave smoke's byte-stability check, natively).
    #[test]
    fn f16_frame_roundtrip_idempotent() {
        let xs: Vec<f32> = (0..1000)
            .map(|i| ((i as f32) * 0.37).sin() * (10.0f32.powi((i % 9) as i32 - 4)))
            .collect();
        let mut buf = Vec::new();
        put_f16s(&mut buf, &xs);
        let mut once = Vec::new();
        let mut off = 0usize;
        take_f16s(&buf, &mut off, &mut once);
        assert_eq!(off, buf.len());
        let mut buf2 = Vec::new();
        put_f16s(&mut buf2, &once);
        assert_eq!(buf, buf2, "f16 → f32 → f16 must be byte-stable");
    }
}
